import test from 'node:test';
import assert from 'node:assert/strict';
import { LRUCache } from './lru.js';

test('set/get/has/size basics', () => {
  const c = new LRUCache(2);
  assert.equal(c.set('a', 1), c);
  c.set('b', 2);
  assert.equal(c.get('a'), 1);
  assert.equal(c.has('b'), true);
  assert.equal(c.has('x'), false);
  assert.equal(c.size, 2);
});

test('evicts least recently used on capacity overflow', () => {
  const c = new LRUCache(2);
  c.set('a', 1);
  c.set('b', 2);
  c.get('a');
  c.set('c', 3);
  assert.equal(c.has('a'), true);
  assert.equal(c.has('b'), false);
  assert.equal(c.get('c'), 3);
});

test('updating existing keys refreshes recency without growing', () => {
  const c = new LRUCache(2);
  c.set('a', 1).set('b', 2).set('a', 10).set('c', 3);
  assert.equal(c.get('a'), 10);
  assert.equal(c.has('b'), false);
  assert.equal(c.size, 2);
});

test('delete, clear, and keys in most-recent-first order', () => {
  const c = new LRUCache(3);
  c.set('a', 1).set('b', 2).set('c', 3);
  c.get('a');
  assert.deepEqual(c.keys(), ['a', 'c', 'b']);
  assert.equal(c.delete('c'), true);
  assert.equal(c.delete('missing'), false);
  assert.deepEqual(c.keys(), ['a', 'b']);
  c.clear();
  assert.equal(c.size, 0);
  assert.deepEqual(c.keys(), []);
});
